1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { useRouter, usePathname } from "next/navigation";
5	import { useAuth } from "@/lib/auth-context";
6	import { Sidebar } from "@/components/layout/sidebar";
7	import { Header } from "@/components/layout/header";
8	import { ScrollArea } from "@/components/ui/scroll-area";
9	import {
10	  Sheet,
11	  SheetContent,
12	  SheetTitle,
13	  SheetDescription,
14	} from "@/components/ui/sheet";
15	
16	interface AppLayoutProps {
17	  children: React.ReactNode;
18	}
19	
20	export function AppLayout({ children }: AppLayoutProps) {
21	  const { user, loading } = useAuth();
22	  const router = useRouter();
23	  const pathname = usePathname();
24	  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
25	  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
26	
27	  const isLoginPage = pathname === "/login";
28	
29	  useEffect(() => {
30	    if (!loading && !user && !isLoginPage) {
31	      router.replace("/login");
32	    }
33	  }, [loading, user, isLoginPage, router]);
34	
35	  // Login page: render directly, no auth check, no sidebar/header
36	  if (isLoginPage) {
37	    return <>{children}</>;
38	  }
39	
40	  if (loading) {
41	    return (
42	      <div className="flex h-screen items-center justify-center">
43	        <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
44	      </div>
45	    );
46	  }
47	
48	  if (!user) {
49	    return null;
50	  }
51	
52	  return (
53	    <div className="flex h-screen flex-col md:flex-row">
54	      {/* Desktop sidebar */}
55	      <aside className="hidden md:flex">
56	        <Sidebar
57	          collapsed={sidebarCollapsed}
58	          onToggleCollapse={() => setSidebarCollapsed((prev) => !prev)}
59	        />
60	      </aside>
61	
62	      {/* Mobile sidebar sheet */}
63	      <Sheet open={mobileSidebarOpen} onOpenChange={setMobileSidebarOpen}>
64	        <SheetContent side="left" className="w-60 p-0">
65	          <SheetTitle className="sr-only">导航菜单</SheetTitle>
66	          <SheetDescription className="sr-only">应用主导航菜单</SheetDescription>
67	          <Sidebar />
68	        </SheetContent>
69	      </Sheet>
70	
71	      {/* Main content area */}
72	      <div className="flex flex-1 flex-col overflow-hidden">
73	        <Header onMenuClick={() => setMobileSidebarOpen(true)} />
74	        <ScrollArea className="flex-1">
75	          <main className="flex-1 p-6">{children}</main>
76	        </ScrollArea>
77	      </div>
78	    </div>
79	  );
80	}
