1	"use client";
2	
3	import Link from "next/link";
4	import { usePathname } from "next/navigation";
5	import { cn } from "@/lib/utils";
6	import { Button } from "@/components/ui/button";
7	import { ScrollArea } from "@/components/ui/scroll-area";
8	import { Separator } from "@/components/ui/separator";
9	import { useAuth, type UserRole } from "@/lib/auth-context";
10	import {
11	  LayoutDashboard,
12	  Laptop,
13	  ClipboardPlus,
14	  Ticket,
15	  Bot,
16	  Bell,
17	  Settings,
18	  CheckSquare,
19	  BarChart3,
20	  Wrench,
21	  Package,
22	  Archive,
23	  Boxes,
24	  ClipboardList,
25	  Users,
26	  FileText,
27	  PieChart,
28	  Lightbulb,
29	  ChevronLeft,
30	  ChevronRight,
31	  type LucideIcon,
32	} from "lucide-react";
33	
34	export type NavItem = {
35	  label: string;
36	  href: string;
37	  icon: LucideIcon;
38	  roles: UserRole[];
39	};
40	
41	const navItems: NavItem[] = [
42	  { label: "首页", href: "/home", icon: LayoutDashboard, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
43	  { label: "我的资产", href: "/my-assets", icon: Laptop, roles: ["EMPLOYEE", "MANAGER"] },
44	  { label: "申领设备", href: "/apply", icon: ClipboardPlus, roles: ["EMPLOYEE", "MANAGER"] },
45	  { label: "我的工单", href: "/tickets", icon: Ticket, roles: ["EMPLOYEE", "MANAGER"] },
46	  { label: "AI 助手", href: "/chat", icon: Bot, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
47	  { label: "通知中心", href: "/notifications", icon: Bell, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
48	  { label: "个人设置", href: "/profile", icon: Settings, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
49	  { label: "审批工作台", href: "/approvals", icon: CheckSquare, roles: ["MANAGER"] },
50	  { label: "部门看板", href: "/dept-board", icon: BarChart3, roles: ["MANAGER"] },
51	  { label: "IT 工作台", href: "/it/home", icon: Wrench, roles: ["IT_ADMIN"] },
52	  { label: "工单工作台", href: "/it/tickets", icon: Ticket, roles: ["IT_ADMIN"] },
53	  { label: "资产管理", href: "/it/assets", icon: Package, roles: ["IT_ADMIN"] },
54	  { label: "型号管理", href: "/it/models", icon: Archive, roles: ["IT_ADMIN"] },
55	  { label: "入库操作", href: "/it/inbound", icon: Boxes, roles: ["IT_ADMIN"] },
56	  { label: "盘点", href: "/it/inventory", icon: ClipboardList, roles: ["IT_ADMIN"] },
57	  { label: "用户管理", href: "/it/users", icon: Users, roles: ["IT_ADMIN"] },
58	  { label: "审计日志", href: "/it/audit", icon: FileText, roles: ["IT_ADMIN"] },
59	  { label: "资产大屏", href: "/exec/dashboard", icon: PieChart, roles: ["EXECUTIVE"] },
60	  { label: "AI 洞察", href: "/exec/insights", icon: Lightbulb, roles: ["EXECUTIVE"] },
61	];
62	
63	function filterNavItems(items: NavItem[], role: UserRole): NavItem[] {
64	  return items.filter((item) => item.roles.includes(role));
65	}
66	
67	interface SidebarProps {
68	  collapsed?: boolean;
69	  onToggleCollapse?: () => void;
70	}
71	
72	export function Sidebar({ collapsed = false, onToggleCollapse }: SidebarProps) {
73	  const pathname = usePathname();
74	  const { user, setRole } = useAuth();
75	  if (!user) return null;
76	  const filteredItems = filterNavItems(navItems, user.role);
77	
78	  const allRoles: UserRole[] = ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"];
79	
80	  return (
81	    <div
82	      className={cn(
83	        "flex h-full flex-col bg-sidebar text-sidebar-foreground transition-all duration-200",
84	        collapsed ? "w-16" : "w-60",
85	      )}
86	    >
87	      {/* Brand area */}
88	      <div
89	        className={cn(
90	          "flex h-14 items-center border-b border-sidebar-border px-4",
91	          collapsed && "justify-center px-2",
92	        )}
93	      >
94	        {collapsed ? (
95	          <div className="flex size-8 items-center justify-center rounded-lg bg-sidebar-primary text-sidebar-primary-foreground text-xs font-bold">
96	            IT
97	          </div>
98	        ) : (
99	          <div className="flex items-center gap-2 overflow-hidden">
100	            <div className="flex size-8 shrink-0 items-center justify-center rounded-lg bg-sidebar-primary text-sidebar-primary-foreground text-xs font-bold">
101	              IT
102	            </div>
103	            <div className="min-w-0 flex-1">
104	              <div className="truncate text-sm font-semibold">资产管理系统</div>
105	              <div className="truncate text-xs text-sidebar-foreground/60">
106	                {user.department} · {user.name}
107	              </div>
108	            </div>
109	          </div>
110	        )}
111	      </div>
112	
113	      {/* Navigation */}
114	      <ScrollArea className="flex-1 px-2 py-2">
115	        <nav className="flex flex-col gap-1">
116	          {filteredItems.map((item) => {
117	            const isActive =
118	              pathname === item.href || pathname.startsWith(item.href + "/");
119	            return (
120	              <Link
121	                key={item.href}
122	                href={item.href}
123	                className={cn(
124	                  "flex items-center gap-3 rounded-md px-2 py-1.5 text-sm font-medium transition-colors",
125	                  "hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
126	                  isActive
127	                    ? "bg-sidebar-accent text-sidebar-accent-foreground"
128	                    : "text-sidebar-foreground/70",
129	                  collapsed && "justify-center px-0 py-2",
130	                )}
131	                title={collapsed ? item.label : undefined}
132	              >
133	                <item.icon className="size-4 shrink-0" />
134	                {!collapsed && <span className="truncate">{item.label}</span>}
135	              </Link>
136	            );
137	          })}
138	        </nav>
139	      </ScrollArea>
140	
141	      {/* Collapse toggle (desktop) */}
142	      {onToggleCollapse && (
143	        <div className="hidden border-t border-sidebar-border md:block">
144	          <Button
145	            variant="ghost"
146	            size="sm"
147	            onClick={onToggleCollapse}
148	            className={cn(
149	              "flex w-full items-center justify-center rounded-none py-2 text-sidebar-foreground/60 hover:text-sidebar-foreground",
150	              collapsed ? "h-10" : "h-8 justify-start gap-2 px-3",
151	            )}
152	          >
153	            {collapsed ? (
154	              <ChevronRight className="size-4" />
155	            ) : (
156	              <>
157	                <ChevronLeft className="size-4" />
158	                <span className="text-xs">收起侧栏</span>
159	              </>
160	            )}
161	          </Button>
162	        </div>
163	      )}
164	
165	      {/* Role Switcher (debug only) */}
166	      <Separator />
167	      <div className="p-2">
168	        {!collapsed && (
169	          <div className="mb-1 px-1 text-[10px] font-medium uppercase tracking-wider text-sidebar-foreground/40">
170	            角色调试
171	          </div>
172	        )}
173	        <div className={cn("flex", collapsed ? "flex-col gap-1" : "flex-wrap gap-1")}>
174	          {allRoles.map((role) => {
175	            const roleLabels: Record<UserRole, string> = {
176	              EMPLOYEE: "员工",
177	              MANAGER: "经理",
178	              IT_ADMIN: "IT",
179	              EXECUTIVE: "高管",
180	            };
181	            const isActive = user.role === role;
182	            return (
183	              <button
184	                key={role}
185	                onClick={() => setRole(role)}
186	                title={collapsed ? roleLabels[role] : undefined}
187	                className={cn(
188	                  "rounded px-1.5 py-0.5 text-[10px] font-medium transition-colors",
189	                  isActive
190	                    ? "bg-sidebar-primary text-sidebar-primary-foreground"
191	                    : "text-sidebar-foreground/50 hover:text-sidebar-foreground",
192	                  collapsed && "px-0 py-1 text-center text-[9px]",
193	                )}
194	              >
195	                {collapsed ? roleLabels[role].slice(0, 2) : roleLabels[role]}
196	              </button>
197	            );
198	          })}
199	        </div>
200	      </div>
201	    </div>
202	  );
203	}
204	
205	export { navItems, filterNavItems };
