3	import { usePathname, useRouter } from "next/navigation";
4	import { Button } from "@/components/ui/button";
5	import { Avatar, AvatarFallback } from "@/components/ui/avatar";
6	import {
7	  DropdownMenu,
8	  DropdownMenuContent,
9	  DropdownMenuItem,
10	  DropdownMenuLabel,
11	  DropdownMenuSeparator,
12	  DropdownMenuTrigger,
13	} from "@/components/ui/dropdown-menu";
14	import { NotificationBell } from "@/components/notification-bell";
15	import { useAuth } from "@/lib/auth-context";
16	import { Menu, LogOut, User as UserIcon } from "lucide-react";
17	import Link from "next/link";
18	
19	interface HeaderProps {
20	  onMenuClick?: () => void;
21	}
22	
23	const breadcrumbLabels: Record<string, string> = {
24	  home: "首页",
25	  "my-assets": "我的资产",
26	  apply: "申领设备",
27	  tickets: "我的工单",
28	  chat: "AI 助手",
29	  notifications: "通知中心",
30	  profile: "个人设置",
31	  approvals: "审批工作台",
32	  "dept-board": "部门看板",
33	  it: "IT 管理",
34	  assets: "资产管理",
35	  models: "型号管理",
36	  inbound: "入库操作",
37	  inventory: "盘点",
38	  users: "用户管理",
39	  audit: "审计日志",
40	  exec: "管理层",
41	  dashboard: "资产大屏",
42	  insights: "AI 洞察",
43	};
44	
45	function buildBreadcrumbs(pathname: string): { label: string; href: string }[] {
46	  const segments = pathname.split("/").filter(Boolean);
47	  const crumbs: { label: string; href: string }[] = [];
48	
49	  let href = "";
50	  for (const segment of segments) {
51	    href += "/" + segment;
52	    crumbs.push({
53	      label: breadcrumbLabels[segment] || segment,
54	      href,
55	    });
56	  }
57	
58	  return crumbs;
59	}
60	
61	export function Header({ onMenuClick }: HeaderProps) {
62	  const pathname = usePathname();
63	  const router = useRouter();
64	  const { user, logout } = useAuth();
65	  const breadcrumbs = buildBreadcrumbs(pathname);
66	
67	  if (!user) return null;
68	
69	  return (
70	    <header className="flex h-14 shrink-0 items-center justify-between border-b bg-background px-4">
71	      {/* Left: Menu button + Breadcrumbs */}
72	      <div className="flex items-center gap-2">
73	        {/* Mobile menu button */}
74	        <Button
75	          variant="ghost"
76	          size="icon-sm"
77	          onClick={onMenuClick}
78	          className="md:hidden"
79	          aria-label="打开菜单"
80	        >
81	          <Menu className="size-4" />
82	        </Button>
83	
84	        {/* Breadcrumbs */}
85	        <nav className="flex items-center gap-1 text-sm text-muted-foreground">
86	          {breadcrumbs.length > 0 ? (
87	            breadcrumbs.map((crumb, index) => (
88	              <span key={crumb.href} className="flex items-center gap-1">
89	                {index > 0 && (
90	                  <span className="text-muted-foreground/40 mx-0.5">/</span>
91	                )}
92	                {index === breadcrumbs.length - 1 ? (
93	                  <span className="font-medium text-foreground">
94	                    {crumb.label}
95	                  </span>
96	                ) : (
97	                  <Link
98	                    href={crumb.href}
99	                    className="hover:text-foreground transition-colors"
100	                  >
101	                    {crumb.label}
102	                  </Link>
103	                )}
104	              </span>
105	            ))
106	          ) : (
107	            <span className="font-medium text-foreground">首页</span>
108	          )}
109	        </nav>
110	      </div>
111	
112	      {/* Right: Notification Bell + User Avatar */}
113	      <div className="flex items-center gap-2">
114	        <NotificationBell />
115	
116	        <DropdownMenu>
117	          <DropdownMenuTrigger className="flex size-7 items-center justify-center rounded-full outline-none focus-visible:ring-2 focus-visible:ring-ring/50">
118	            <Avatar size="sm">
119	              <AvatarFallback>
120	                {user.name.slice(0, 2)}
121	              </AvatarFallback>
122	            </Avatar>
123	          </DropdownMenuTrigger>
124	          <DropdownMenuContent align="end" className="w-48">
125	            <DropdownMenuLabel>
126	              <div className="flex flex-col">
127	                <span className="text-sm font-medium">{user.name}</span>
128	                <span className="text-xs font-normal text-muted-foreground">
129	                  {user.email}
130	                </span>
131	              </div>
132	            </DropdownMenuLabel>
133	            <DropdownMenuSeparator />
134	            <DropdownMenuItem onClick={() => router.push("/profile")}>
135	              <UserIcon className="size-4" />
136	              个人设置
137	            </DropdownMenuItem>
138	            <DropdownMenuSeparator />
139	            <DropdownMenuItem
140	              onClick={logout}
141	              className="flex items-center gap-2 text-destructive focus:text-destructive"
142	            >
143	              <LogOut className="size-4" />
144	              退出登录
145	            </DropdownMenuItem>
146	          </DropdownMenuContent>
147	        </DropdownMenu>
148	      </div>
149	    </header>
150	  );
151	}
