1	"use client";
2	
3	import React, {
4	  createContext,
5	  useCallback,
6	  useContext,
7	  useEffect,
8	  useMemo,
9	  useState,
10	} from "react";
11	import { apiFetch, setToken, clearToken, getToken } from "./api-client";
12	
13	export type UserRole = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
14	
15	export interface User {
16	  id: string;
17	  name: string;
18	  email: string;
19	  role: UserRole;
20	  avatar?: string;
21	  department: string;
22	  departmentId: string;
23	}
24	
25	interface LoginResponse {
26	  token: string;
27	  user: User;
28	}
29	
30	interface SessionResponse {
31	  user: User;
32	}
33	
34	interface AuthContextType {
35	  user: User | null;
36	  token: string | null;
37	  loading: boolean;
38	  login: (email: string, password: string) => Promise<void>;
39	  loginAsDemo: (role: UserRole) => void;
40	  logout: () => void;
41	  setRole: (role: UserRole) => void;
42	  unreadNotifications: number;
43	  setUnreadNotifications: (n: number) => void;
44	}
45	
46	const AuthContext = createContext<AuthContextType | null>(null);
47	
48	const demoUsers: Record<UserRole, User> = {
49	  EMPLOYEE:  { id: "demo-emp",  name: "张三", email: "zhangsan@example.com",   role: "EMPLOYEE",  department: "技术部", departmentId: "dept-tech" },
50	  MANAGER:   { id: "demo-mgr",  name: "李四", email: "lisi@example.com",       role: "MANAGER",   department: "技术部", departmentId: "dept-tech" },
51	  IT_ADMIN:  { id: "demo-it",   name: "王五", email: "wangwu@example.com",     role: "IT_ADMIN",  department: "IT 部", departmentId: "dept-it" },
52	  EXECUTIVE: { id: "demo-exec", name: "赵六", email: "zhaoliu@example.com",    role: "EXECUTIVE", department: "管理层", departmentId: "dept-mgmt" },
53	};
54	
55	export function AuthProvider({ children }: { children: React.ReactNode }) {
56	  const [user, setUser] = useState<User | null>(null);
57	  const [token, setTokenState] = useState<string | null>(null);
58	  const [loading, setLoading] = useState(true);
59	  const [unreadNotifications, setUnreadNotifications] = useState(0);
60	
61	  // Restore session on mount
62	  useEffect(() => {
63	    const storedToken = getToken();
64	    // Clear any stale demo token — real API is needed now
65	    if (storedToken && storedToken.startsWith("demo-token-")) {
66	      clearToken();
67	      setLoading(false);
68	      return;
69	    }
70	    if (storedToken) {
71	      setTokenState(storedToken);
72	      apiFetch<SessionResponse>("/api/auth/session")
73	        .then((data) => {
74	          setUser(data.user);
75	        })
76	        .catch(() => {
77	          // Session invalid, clear token
78	          clearToken();
79	          setTokenState(null);
80	          setUser(null);
81	        })
82	        .finally(() => {
83	          setLoading(false);
84	        });
85	    } else {
86	      setLoading(false);
87	    }
88	  }, []);
89	
90	  const login = useCallback(async (email: string, password: string) => {
91	    const data = await apiFetch<LoginResponse>("/api/auth/login", {
92	      method: "POST",
93	      body: JSON.stringify({ email, password }),
94	    });
95	    setToken(data.token);
96	    setTokenState(data.token);
97	    setUser(data.user);
98	  }, []);
99	
100	  const loginAsDemo = useCallback((role: UserRole) => {
101	    const demoUser = demoUsers[role];
102	    const fakeToken = "demo-token-" + role + "-" + Date.now();
103	    setToken(fakeToken);
104	    setTokenState(fakeToken);
105	    setUser(demoUser);
106	  }, []);
107	
108	  const logout = useCallback(() => {
109	    // Fire and forget the logout request
110	    apiFetch("/api/auth/logout", { method: "POST" }).catch(() => {
111	      // ignore errors
112	    });
113	    clearToken();
114	    setTokenState(null);
115	    setUser(null);
116	  }, []);
117	
118	  const setRole = useCallback(
119	    (role: UserRole) => {
120	      setUser((prev) => (prev ? { ...prev, role } : prev));
121	    },
122	    [],
123	  );
124	
125	  const value = useMemo<AuthContextType>(
126	    () => ({
127	      user,
128	      token,
129	      loading,
130	      login,
131	      loginAsDemo,
132	      logout,
133	      setRole,
134	      unreadNotifications,
135	      setUnreadNotifications,
136	    }),
137	    [user, token, loading, login, loginAsDemo, logout, setRole, unreadNotifications],
138	  );
139	
140	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
141	}
142	
143	export function useAuth(): AuthContextType {
144	  const ctx = useContext(AuthContext);
145	  if (!ctx) {
146	    throw new Error("useAuth must be used within an AuthProvider");
147	  }
148	  return ctx;
149	}
